import React from 'react';
import { Card, CardContent, Box, Typography, Stack, IconButton } from '@mui/material';
import { PlayArrow, Pause, Repeat, Shuffle } from '@mui/icons-material';
import response from './response.json';

interface PlaybackControls {
  isPlaying: boolean;
  volume: number;
  repeat: boolean;
  shuffle: boolean;
}

interface CurrentlyPlaying {
  track: string;
  artist: string;
  album: string;
  duration: string;
  progress: string;
  playbackControls: PlaybackControls;
}

interface WidgetData {
  currentlyPlaying: CurrentlyPlaying;
}

export default function Widget() {
  const { currentlyPlaying } = response.data as WidgetData;
  const { track, artist, album, duration, progress, playbackControls } = currentlyPlaying;
  const { isPlaying, repeat, shuffle } = playbackControls;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: '#191414' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B3B3B3' }}>
              Now Playing
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFFFFF', my: 0.5 }}>
              {track}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B3B3B3' }}>
              {artist} - {album}
            </Typography>
          </Box>

          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: '#B3B3B3' }}>
            <Typography variant="caption">{progress}</Typography>
            <Typography variant="caption">{duration}</Typography>
          </Box>

          <Stack direction="row" spacing={1} justifyContent="center">
            <IconButton sx={{ color: shuffle ? '#1DB954' : '#B3B3B3' }}>
              <Shuffle />
            </IconButton>
            <IconButton sx={{ color: '#1DB954' }}>
              {isPlaying ? <Pause /> : <PlayArrow />}
            </IconButton>
            <IconButton sx={{ color: repeat ? '#1DB954' : '#B3B3B3' }}>
              <Repeat />
            </IconButton>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
